impl.spec_text:
spec fn f(i: int, j: int) -> bool {
    i <= j
}

proof fn test_choose_eq() {
    let (i1, j1): (int, int) = choose|i: int, j: int| f(i, j) && (2 + 2 == 4);
    let (i2, j2): (int, int) = choose|i: int, j: int| (2 + 2 == 4) && f(i, j);
    // requires extensional equality
    assert(i1 == i2); // FAILS
}

